import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function MyAppointments() {
  const [appointments, setAppointments] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    api.get("/customer/appointments/my")
      .then((res) => setAppointments(res.data))
      .catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, []);

  return (
    <div style={{ padding: 20 }}>
      <h2>My Appointments</h2>

      {appointments.map((a) => (
        <div
          key={a._id}
          style={{
            border: "1px solid #ddd",
            padding: 12,
            marginBottom: 12,
            borderRadius: 8,
          }}
        >
          <div><b>Vehicle:</b> {a.vehicle?.brand} {a.vehicle?.model || a.vehicle?.type || ""}</div>
          <div><b>Date:</b> {new Date(a.date).toLocaleDateString()}</div>
          <div><b>Time:</b> {a.time}</div>
          <div><b>Status:</b> {a.status}</div>

          <div style={{ marginTop: 10 }}>
            <button
              onClick={() => navigate(`/edit-my-appointment/${a._id}`)}
              style={{ marginRight: 8 }}
              disabled={a.status !== "scheduled"} // prevent editing completed/cancelled
            >
              Edit
            </button>
          </div>
        </div>
      ))}

      {appointments.length === 0 && <p>No appointments yet.</p>}
    </div>
  );
}
